<?php require_once __DIR__ . '/../includes/admin.php'; admin_required(); $projects=db()->query('SELECT * FROM projects ORDER BY created_at DESC')->fetchAll(); admin_head('Projects'); ?><h1>Projects <a class="button" href="<?=url('admin/add-project.php')?>">Add project</a></h1><div class="card"><table><tr><th>Image</th><th>Project</th><th class="hide-mobile">Location</th><th>Status</th><th></th></tr><?php foreach($projects as $p):?><tr><td><img class="thumb" src="<?=url($p['thumbnail'])?>" alt=""></td><td><?=e($p['project_name'])?></td><td class="hide-mobile"><?=e($p['location'])?></td><td><?=e($p['status'])?></td><td><a class="button" href="<?=url('admin/edit-project.php?id='.(int)$p['id'])?>">Edit</a> <form style="display:inline" method="post" action="<?=url('admin/delete-project.php')?>"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="id" value="<?=$p['id']?>"><button class="danger" onclick="return confirm('Delete this project?')">Delete</button></form></td></tr><?php endforeach?></table></div><?php admin_foot(); ?>
